@app.route("/leaderboard")
@app.route("/leaderboard/<queue_id>")
def leaderboard(queue_id=None):
    conn = get_db()
    try:
        if queue_id and queue_id in QUEUES:
            players = conn.execute("""
                SELECT p.username, p.discord_id, p.wins, p.losses,
                       q.elo, q.wins as qwins, q.losses as qlosses, q.placement_done
                FROM player_queue_elo q
                JOIN players p ON p.discord_id = q.discord_id
                WHERE q.queue_id = ? AND q.placement_done = 1
                ORDER BY q.elo DESC
            """, (queue_id,)).fetchall()
            queue_name = QUEUES[queue_id]["name"]
        else:
            queue_id = None
            players = conn.execute("SELECT username, discord_id, elo, wins, losses FROM players ORDER BY elo DESC").fetchall()
            queue_name = "Global"
    except:
        players = []; queue_name = "Global"
    conn.close()

    tabs = f'''<a href="/leaderboard" class="tab {"active" if not queue_id else ""}">Global</a>'''
    for qid, q in QUEUES.items():
        tabs += f'''<a href="/leaderboard/{qid}" class="tab {"active" if queue_id==qid else ""}">{q["emoji"]} {q["name"]}</a>'''

    rows = ""
    for i, p in enumerate(players):
        elo = sc(p,"elo",1000) or 1000
        w = sc(p,"wins",0) or 0; l = sc(p,"losses",0) or 0
        t = w+l; wr = round(w/t*100) if t>0 else 0
        rn, rc, _ = get_rank(elo)
        pc = ["g","s","b"][i] if i<3 else ""
        ps = ["🥇","🥈","🥉"][i] if i<3 else f"#{i+1}"
        rows += f'''<tr>
          <td><span class="pos {pc}">{ps}</span></td>
          <td><div style="font-weight:700">{p["username"]}</div><div style="font-size:.75rem;color:{rc}">{rn}</div></td>
          <td><span class="elo-badge" style="background:{rc}22;color:{rc}">{elo}</span></td>
          <td style="font-family:JetBrains Mono,monospace;font-size:.82rem">{w}W / {l}L</td>
          <td><div class="wr-row"><div class="wr-bar"><div class="wr-fill" style="width:{wr}%"></div></div><span style="font-size:.78rem;font-family:JetBrains Mono,monospace">{wr}%</span></div></td>
        </tr>'''

    if not rows:
        rows = '<tr><td colspan="5"><div class="empty"><div class="empty-icon">👻</div><h3>Aucun joueur classé</h3><p>Les joueurs apparaissent après leurs matchs de placement</p></div></td></tr>'

    body = f'''
    <div class="ph"><h1>CLASSEMENT</h1><p>{queue_name} — {len(players)} joueur(s) classé(s)</p></div>
    <div class="tabs">{tabs}</div>
    <div class="table-wrap">
      <table>
        <thead><tr><th>#</th><th>Joueur</th><th>ELO</th><th>W / L</th><th>Winrate</th></tr></thead>
        <tbody>{rows}</tbody>
      </table>
    </div>'''
    return page(f"Classement {queue_name}", body)


@app.route("/matches")
def matches():
    conn = get_db()
    try:
        all_matches = conn.execute("SELECT team1, team2, map, winner, created_at FROM matches WHERE status='completed' ORDER BY created_at DESC LIMIT 50").fetchall()
        pdb = {r["discord_id"]: r["username"] for r in conn.execute("SELECT discord_id, username FROM players").fetchall()}
    except:
        all_matches = []; pdb = {}
    conn.close()

    cards = ""
    for m in all_matches:
        try:
            t1 = json.loads(m["team1"]); t2 = json.loads(m["team2"])
            t1n = [pdb.get(pid,"?") for pid in t1[:3]]; t2n = [pdb.get(pid,"?") for pid in t2[:3]]
            w = sc(m,"winner",0) or 0
            s1 = "color:var(--purple3);font-weight:700" if w==1 else ""
            s2 = "color:var(--purple3);font-weight:700" if w==2 else ""
            date = (sc(m,"created_at","") or "")[:10]
            cards += f'''<div class="match-row">
              <div class="match-team" style="{s1}">{"🏆 " if w==1 else ""}Équipe 1<br><small style="color:var(--muted);font-weight:400;font-size:.75rem">{", ".join(t1n)}{"…" if len(t1)>3 else ""}</small></div>
              <div class="match-mid"><div class="match-score">{"WIN" if w else "VS"}</div><div class="map-tag">{sc(m,"map","—") or "—"}</div><div class="match-meta">{date}</div></div>
              <div class="match-team r" style="{s2}">{"🏆 " if w==2 else ""}Équipe 2<br><small style="color:var(--muted);font-weight:400;font-size:.75rem">{", ".join(t2n)}{"…" if len(t2)>3 else ""}</small></div>
            </div>'''
        except: pass

    if not cards:
        cards = '<div class="empty"><div class="empty-icon">⚔️</div><h3>Aucun match terminé</h3><p>Les matchs apparaissent ici une fois validés</p></div>'

    body = f'''<div class="ph"><h1>HISTORIQUE DES MATCHS</h1><p>50 derniers matchs terminés</p></div>
    <div class="match-list">{cards}</div>'''
    return page("Matchs", body)


@app.route("/player/<discord_id>")
def player_profile(discord_id):
    conn = get_db()
    try: p = conn.execute("SELECT * FROM players WHERE discord_id=?", (discord_id,)).fetchone()
    except: p = None
    if not p: conn.close(); abort(404)
    try: qelos = conn.execute("SELECT * FROM player_queue_elo WHERE discord_id=?", (discord_id,)).fetchall()
    except: qelos = []
    try:
        recent = conn.execute("SELECT team1, team2, winner, map, created_at FROM matches WHERE (team1 LIKE ? OR team2 LIKE ?) AND status='completed' ORDER BY created_at DESC LIMIT 10", (f'''%{discord_id}%''', f'''%{discord_id}%''')).fetchall()
    except: recent = []
    conn.close()

    rn, rc, _ = get_rank(p["elo"])
    t = p["wins"]+p["losses"]; wr = round(p["wins"]/t*100) if t>0 else 0
    ini = (p["username"] or "??")[:2].upper()

    qrows = ""
    for q in qelos:
        qn = QUEUES.get(q["queue_id"],{}).get("name", q["queue_id"])
        qr, qc, _ = get_rank(q["elo"])
        qt = q["wins"]+q["losses"]; qwr = round(q["wins"]/qt*100) if qt>0 else 0
        st = "Classé" if q["placement_done"] else f"Placement ({qt}/10)"
        qrows += f'''<tr><td style="font-weight:600">{qn}</td><td><span class="elo-badge" style="background:{qc}22;color:{qc}">{q["elo"]}</span></td><td style="color:{qc};font-size:.82rem">{qr}</td><td style="font-family:JetBrains Mono,monospace;font-size:.82rem">{q["wins"]}W / {q["losses"]}L ({qwr}%)</td><td style="color:var(--muted);font-size:.78rem">{st}</td></tr>'''

    mrows = ""
    for m in recent:
        try:
            t1i = json.loads(m["team1"]); my = 1 if discord_id in t1i else 2
            w = sc(m,"winner",0) or 0; won = w==my
            rc2 = "#57f287" if won else "#ed4245"
            mrows += f'''<tr><td style="color:{rc2};font-weight:700">{"✅ Victoire" if won else "❌ Défaite"}</td><td>{sc(m,"map","—") or "—"}</td><td style="color:var(--muted);font-size:.78rem">{(sc(m,"created_at","") or "")[:10]}</td></tr>'''
        except: pass

    body = f'''
    <div class="profile-top">
      <div class="avatar">{ini}</div>
      <div><div class="pname">{p["username"]}</div><div class="priot">{sc(p,"riot_id","") or "Riot ID non renseigné"}</div></div>
      <div class="pelo"><div class="elo-big" style="color:{rc}">{p["elo"]}</div><div style="color:{rc};font-size:.85rem">{rn}</div><div style="color:var(--muted);font-size:.78rem;margin-top:4px">{p["wins"]}V / {p["losses"]}D · {wr}%</div></div>
    </div>
    <div class="section-title" style="font-size:1.4rem">ELO par Queue</div>
    <div class="table-wrap" style="margin-bottom:2rem"><table><thead><tr><th>Queue</th><th>ELO</th><th>Rang</th><th>Stats</th><th>Statut</th></tr></thead><tbody>{qrows if qrows else '<tr><td colspan="5" style="text-align:center;padding:2rem;color:var(--muted)">Aucune queue jouée</td></tr>'}</tbody></table></div>
    <div class="section-title" style="font-size:1.4rem">Derniers matchs</div>
    <div class="table-wrap"><table><thead><tr><th>Résultat</th><th>Map</th><th>Date</th></tr></thead><tbody>{mrows if mrows else '<tr><td colspan="3" style="text-align:center;padding:2rem;color:var(--muted)">Aucun match</td></tr>'}</tbody></table></div>
    '''
    return page(p["username"], body)


@app.route("/api/stats")
def api_stats():
    conn = get_db()
    try: stats = {"players": conn.execute("SELECT COUNT(*) FROM players").fetchone()[0], "matches": conn.execute("SELECT COUNT(*) FROM matches WHERE status='completed'").fetchone()[0]}
    except: stats = {"players":0,"matches":0}
    conn.close()
    return jsonify(stats)


def run_web():
    port = int(os.getenv("PORT", 8080))
    app.run(host="0.0.0.0", port=port, debug=False)

def start_web_server():
    t = Thread(target=run_web, daemon=True)
    t.start()
    print(f"✅ Serveur web démarré (port {os.getenv('PORT', 8080)})")
